import{_ as e,o as a,c as o,a5 as i}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"速度环与负载转矩观测器仿真 -- 阶跃启动 + 负载扰动 + TL 前馈补偿","description":"","frontmatter":{"title":"速度环与负载转矩观测器仿真 -- 阶跃启动 + 负载扰动 + TL 前馈补偿","date":"2026-07-02T00:00:00.000Z","section":"电机控制","chapter":"02-Simulations","chapterTitle":"仿真专题","category":"电机控制","tags":["imported"],"source":"motor","sourcePath":"frontend/src/components/simulations/SpeedLoopSim.vue","status":"learning","visibility":"public","summary":"Imported from frontend/src/components/simulations/SpeedLoopSim.vue","chapterOrder":20},"headers":[],"relativePath":"content/motor/simulations/SpeedLoopSim.md","filePath":"content/motor/simulations/SpeedLoopSim.md","lastUpdated":null}'),r={name:"content/motor/simulations/SpeedLoopSim.md"};function n(p,t,s,l,c,d){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="速度环与负载转矩观测器仿真-阶跃启动-负载扰动-tl-前馈补偿" tabindex="-1">速度环与负载转矩观测器仿真 -- 阶跃启动 + 负载扰动 + TL 前馈补偿 <a class="header-anchor" href="#速度环与负载转矩观测器仿真-阶跃启动-负载扰动-tl-前馈补偿" aria-label="Permalink to &quot;速度环与负载转矩观测器仿真 -- 阶跃启动 + 负载扰动 + TL 前馈补偿&quot;">​</a></h1><h4 id="速度环与负载转矩观测器仿真-阶跃启动-负载扰动-tl-前馈补偿-1" tabindex="-1">速度环与负载转矩观测器仿真 -- 阶跃启动 + 负载扰动 + TL 前馈补偿 <a class="header-anchor" href="#速度环与负载转矩观测器仿真-阶跃启动-负载扰动-tl-前馈补偿-1" aria-label="Permalink to &quot;速度环与负载转矩观测器仿真 -- 阶跃启动 + 负载扰动 + TL 前馈补偿&quot;">​</a></h4><h2 id="速度环-pi-整定与负载转矩观测器原理" tabindex="-1">速度环 PI 整定与负载转矩观测器原理 <a class="header-anchor" href="#速度环-pi-整定与负载转矩观测器原理" aria-label="Permalink to &quot;速度环 PI 整定与负载转矩观测器原理&quot;">​</a></h2><p>**级联结构：**FOC 采用速度环（外环）+ 电流环（内环）的级联控制。速度环输出 Iq_ref 作为电流环给定，速度环带宽通常设为电流环的 1/5~1/10，本仿真用 10kHz 电流环 vs 1kHz 速度环做学习对照。</p><p>**运动方程：**J·dω/dt = Kt·Iq - TL - B·ω。忽略摩擦项后，被控对象为纯积分环节 G(s) = Kt/(Js)，使用对称最优法 (SO) 整定 PI 参数。</p><p>**对称最优法：**Kp = J·ωc/Kt，Ki = Kp·ωc/a²（a=2~4）。SO 法保证足够的相角裕度，但阶跃响应超调约 43%，需加前置滤波器。</p><p>**Gopinath 降阶观测器：**将负载转矩 TL 建模为缓变扰动 (dTL/dt ≈ 0)，通过标量增益 l 估计 TL，仅需 2 个状态变量，实现极简，适合 MCU 实时运行。</p><p>**前馈补偿：**将观测器估计的 TL 折算为等效 Iq 电流 Iqbff = TL/Kt，叠加到 PI 输出上。前馈补偿可使负载扰动速度跌落减小 60~80%，恢复时间加快 3~5 倍。</p><p>**抗积分饱和：**速度环 Iq 指令频繁触及限幅值，必须使用 Clamping + Back-calculation 组合策略防止 Windup。关闭抗饱和可观察到明显的超调恶化。</p>',9)])])}const h=e(r,[["render",n]]);export{u as __pageData,h as default};
